class Solution:
    def findKthNumber(self, m: int, n: int, k: int) -> int:
        lo,hi=1,m*n
        def cnt(x):
            c=0
            for i in range(1,m+1): c+=min(x//i,n)
            return c
        while lo<hi:
            mid=(lo+hi)//2
            if cnt(mid)>=k: hi=mid
            else: lo=mid+1
        return lo

